#include <stdio.h>
#include <stdint.h>

// fast doubling: returns (F(n), F(n+1)) modulo mod
static void fib(uint64_t n, uint64_t mod, uint64_t *fn, uint64_t *fn1) {
    if (n == 0) { *fn = 0; *fn1 = 1 % mod; return; }
    uint64_t a, b;
    fib(n >> 1, mod, &a, &b); // a = F(k), b = F(k+1)
    uint64_t c = (a * ((2 * b % mod + mod) - a)) % mod; // F(2k)
    uint64_t d = (a * a % mod + b * b % mod) % mod;      // F(2k+1)
    if ((n & 1) == 0) {
        *fn = c;
        *fn1 = d;
    } else {
        *fn = d;
        *fn1 = (c + d) % mod;
    }
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N, M; scanf("%llu %llu", &N, &M);
        uint64_t k = 2 * N; // we need F_{2N} and F_{2N-1}
        uint64_t fk, fk1;
        fib(k, M, &fk, &fk1); // fk = F_{2N}, fk1 = F_{2N+1}
        // F_{2N-1} = (fk1 - fk) mod M
        uint64_t fkm1 = (fk1 + M - fk) % M;
        printf("%llu/%llu\n", fkm1, fk);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
using int64 = long long;

pair<int64,int64> fib(int64 n, int64 mod) {
    if (n == 0) return {0, 1 % mod};
    auto p = fib(n >> 1, mod);
    int64 a = p.first;   // F(k)
    int64 b = p.second;  // F(k+1)
    int64 c = (a * ((2 * b % mod + mod) - a)) % mod;          // F(2k)
    int64 d = (a * a % mod + b * b % mod) % mod;              // F(2k+1)
    if ((n & 1) == 0) return {c, d};
    else return {d, (c + d) % mod};
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        long long N, M; cin >> N >> M;
        long long k = 2 * N;
        auto pr = fib(k, M); // pr.first = F_{2N}, pr.second = F_{2N+1}
        long long F2N = pr.first;
        long long F2Nplus1 = pr.second;
        long long F2Nminus1 = (F2Nplus1 + M - F2N) % M;
        cout << F2Nminus1 << '/' << F2N << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static long MOD;
    static long[] fibPair(long n) { // returns {F(n), F(n+1)} modulo MOD
        if (n == 0) return new long[]{0, 1 % MOD};
        long[] p = fibPair(n >> 1);
        long a = p[0]; // F(k)
        long b = p[1]; // F(k+1)
        long c = (a * ((2 * b % MOD + MOD) - a)) % MOD; // F(2k)
        long d = (a * a % MOD + b * b % MOD) % MOD;     // F(2k+1)
        if ((n & 1) == 0) return new long[]{c, d};
        else return new long[]{d, (c + d) % MOD};
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long N = Long.parseLong(st.nextToken());
            MOD = Long.parseLong(st.nextToken());
            long k = 2L * N;
            long[] pr = fibPair(k); // pr[0]=F_{2N}, pr[1]=F_{2N+1}
            long f2n = pr[0];
            long f2nPlus1 = pr[1];
            long f2nMinus1 = (f2nPlus1 + MOD - f2n) % MOD;
            out.append(f2nMinus1).append('/').append(f2n).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def fib(n, mod):
    if n == 0:
        return (0, 1 % mod)
    a, b = fib(n >> 1, mod)  # a=F(k), b=F(k+1)
    c = (a * ((2 * b % mod + mod) - a)) % mod          # F(2k)
    d = (a * a % mod + b * b % mod) % mod              # F(2k+1)
    if n & 1:
        return (d, (c + d) % mod)
    else:
        return (c, d)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        M = int(next(it))
        k = 2 * N
        f2n, f2n_plus1 = fib(k, M)  # f2n = F_{2N}, f2n_plus1 = F_{2N+1}
        f2n_minus1 = (f2n_plus1 - f2n) % M
        out_lines.append(f"{f2n_minus1}/{f2n}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

