const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let result = [];
function fib(n, mod) { // returns [F(n), F(n+1)] as BigInt
    if (n === 0n) return [0n, 1n % mod];
    const half = n >> 1n;
    const [a, b] = fib(half, mod); // a=F(k), b=F(k+1)
    const twoB = (2n * b) % mod;
    const c = (a * ((twoB + mod - a) % mod)) % mod; // F(2k)
    const d = (a * a % mod + b * b % mod) % mod;   // F(2k+1)
    if (n & 1n) {
        return [d, (c + d) % mod];
    } else {
        return [c, d];
    }
}
for (let t = 0; t < T; ++t) {
